// ============================================================================
// Validate Issue Contract
// Prüft: Labels, Modus, Approvals, Akzeptanzkriterien
// ============================================================================

const issueData = $input.first().json;

// Issue-Daten auslesen (von GitHub Get Issue oder Manual Trigger)
const owner = issueData.owner || 'xxammaxx';
const repo = issueData.repo || 'n8n-blueprint-workflow';
const issueNumber = issueData.issue_number;
const issueUrl = `https://github.com/${owner}/${repo}/issues/${issueNumber}`;
const issueTitle = issueData.title || '';
const issueBody = issueData.body || '';
const labels = issueData.labels || [];

// Labels extrahieren
const labelNames = labels.map(l => typeof l === 'string' ? l : l.name).filter(Boolean);
const hasQueued = labelNames.includes('agent:queued');
const hasReady = labelNames.includes('agent:ready');
const hasRunning = labelNames.includes('agent:running');
const hasBlocked = labelNames.includes('agent:blocked');
const hasDone = labelNames.includes('agent:done');

// Modus erkennen
let mode = 'manual-terminal';
if (labelNames.includes('mode:opencode-run')) mode = 'opencode-run';
else if (labelNames.includes('mode:hermes-review')) mode = 'hermes-review';
else if (labelNames.includes('mode:manual-terminal')) mode = 'manual-terminal';

// Risiko erkennen
let risk = 'medium';
if (labelNames.includes('risk:low')) risk = 'low';
else if (labelNames.includes('risk:high')) risk = 'high';

// Nur agent:ready oder agent:queued Issues verarbeiten
const shouldRun = hasReady || hasQueued;
const isAlreadyRunning = hasRunning;
const isAlreadyDone = hasDone;
const isBlocked = hasBlocked;

// Contract prüfen
const hasTask = issueBody.includes('Aufgabe');
const hasAcceptance = issueBody.includes('Akzeptanzkriterien');
const hasVerification = issueBody.includes('Verification Contract');

const validation = {
  valid: shouldRun && !isAlreadyRunning && !isAlreadyDone && !isBlocked,
  has_task: hasTask,
  has_acceptance: hasAcceptance,
  has_verification: hasVerification,
  reason: ''
};

if (!shouldRun) {
  validation.reason = 'Issue hat nicht agent:ready oder agent:queued Label';
} else if (isAlreadyRunning) {
  validation.reason = 'Issue läuft bereits (agent:running)';
} else if (isAlreadyDone) {
  validation.reason = 'Issue bereits abgeschlossen (agent:done)';
} else if (isBlocked) {
  validation.reason = 'Issue ist blockiert (agent:blocked)';
}

return {
  owner,
  repo,
  issue_number: issueNumber,
  issue_url: issueUrl,
  issue_title: issueTitle,
  labels: labelNames,
  mode,
  risk,
  validation,
  has_ready: hasReady,
  has_queued: hasQueued
};

// ============================================================================
// Prepare RUN_INPUT.json
// Erzeugt die RUN_INPUT-Struktur mit GitHub Source-of-Truth-Feldern
// ============================================================================

const ctx = $input.first().json;

// Nur weitermachen, wenn valid
if (!ctx.validation || !ctx.validation.valid) {
  throw new Error('Issue validation failed: ' + (ctx.validation.reason || 'unknown'));
}

// Run-ID generieren
const now = new Date();
const ts = now.toISOString().replace(/[-:]/g, '').replace(/\.\d{3}/, '');
const runId = `gh-issue-${ctx.issue_number}-${ts}`;

// OpenCode-Status abfragen (fest codiert, bis OpenCode Provider hat)
const opencodeAvailable = true;    // v1.17.9 ist installiert
const opencodeVersion = 'v1.17.9';
const opencodeProviderConfigured = false;  // Provider/Auth fehlt
const hermesAvailable = false;  // Hermes nicht installiert

const runInput = {
  run_id: runId,
  source_of_truth: 'github',
  github: {
    owner: ctx.owner,
    repo: ctx.repo,
    issue_number: ctx.issue_number,
    issue_url: ctx.issue_url,
    trigger_label: ctx.has_ready ? 'agent:ready' : 'agent:queued'
  },
  mode: ctx.mode,
  risk: ctx.risk,
  approval_policy: {
    push: false,
    pr: false,
    merge: false,
    github_actions: false,
    provider_config: false
  },
  runner: {
    workspace_root: '/opt/dev-fabric/workspaces/projects',
    evidence_root: '/opt/dev-fabric/evidence/github-agent-runs'
  },
  agent_runtime: {
    opencode_available: opencodeAvailable,
    opencode_version: opencodeVersion,
    opencode_provider_configured: opencodeProviderConfigured,
    hermes_available: hermesAvailable
  },
  // Issue-Kontext für Evidence
  issue_context: {
    title: ctx.issue_title,
    labels: ctx.labels,
    mode: ctx.mode,
    risk: ctx.risk
  }
};

return {
  run_input: runInput,
  run_input_json: JSON.stringify(runInput, null, 2),
  run_id: runId,
  issue_number: ctx.issue_number,
  issue_url: ctx.issue_url,
  owner: ctx.owner,
  repo: ctx.repo,
  mode: ctx.mode
};

// ============================================================================
// Format Evidence Comment
// Bereitet den Issue-Kommentar aus Runner Evidence vor
// ============================================================================

const prepData = $('Prepare RUN_INPUT.json').first().json;
const statusOutput = $input.first().json;

let status = 'UNKNOWN';
let runId = prepData.run_id || 'unknown';
let effectiveMode = prepData.mode || 'manual-terminal';
let opencodeAvailable = 'PASS (v1.17.9)';
let opencodeProviderConfigured = 'NO';
let evidencePaths = {};

try {
  if (typeof statusOutput === 'string') {
    const parsed = JSON.parse(statusOutput);
    status = parsed.status || status;
    effectiveMode = (parsed.mode && parsed.mode.effective) || effectiveMode;
    if (parsed.agent_runtime) {
      opencodeAvailable = parsed.agent_runtime.opencode_available ? 'PASS (' + (parsed.agent_runtime.opencode_version || 'v1.17.9') + ')' : 'FAIL';
      opencodeProviderConfigured = parsed.agent_runtime.opencode_provider_configured ? 'YES' : 'NO';
    }
    if (parsed.evidence_paths) {
      evidencePaths = parsed.evidence_paths;
    }
  } else if (typeof statusOutput === 'object') {
    status = statusOutput.status || statusOutput.error || status;
    if (statusOutput.evidence_paths) {
      evidencePaths = statusOutput.evidence_paths;
    }
  }
} catch (e) {
  status = 'GREEN_PARTIAL (parse error: ' + e.message + ')';
}

const commentBody = `## Agent Run Result

**Status:** ${status}

**Run ID:** ${runId}
**Mode:** ${effectiveMode}
**Source of Truth:** GitHub Issue
**Runner:** lxc-dev-runner / 192.168.1.53

### Evidence

Local evidence path:

\`\`\`text
${evidencePaths.run_dir || '/opt/dev-fabric/evidence/github-agent-runs/' + prepData.owner + '/' + prepData.repo + '/issue-' + prepData.issue_number + '/' + runId + '/'}
\`\`\`

### Verification

| Check                        | Result |
| ---------------------------- | ------ |
| RUN_INPUT validated          | PASS   |
| Runner started               | PASS   |
| Evidence written             | PASS   |
| OpenCode available           | ${opencodeAvailable} |
| OpenCode provider configured | ${opencodeProviderConfigured} |

### Changed files

No repository files changed by the agent run.

### Approval state

* Push: not approved
* PR: not approved
* Merge: not approved
* GitHub Actions: not approved
* Provider/API-Key configuration: not approved

### Next step

Issue kann geschlossen oder mit \`agent:needs-review\` markiert werden.

### Was kann das System jetzt im Vergleich zum vorherigen Lauf?

- GitHub Issues dienen als Agenten-Auftrag (Source of Truth)
- n8n liest Issue-Kontext und erzeugt RUN_INPUT.json
- Runner schreibt Evidence unter issue-bezogenem Pfad
- Issue-Kommentar dient als Evidence-Zusammenfassung
- OpenCode v1.17.9 ist als Runtime erkannt, aber ohne Provider/Auth
`;

return {
  issue_url: prepData.issue_url,
  issue_number: prepData.issue_number,
  owner: prepData.owner,
  repo: prepData.repo,
  run_id: runId,
  status: status,
  comment_body: commentBody,
  comment_preview: commentBody.substring(0, 200) + '...'
};

// ============================================================================
// Final Result / Log Output
// ============================================================================

const data = $input.first().json;

const result = {
  status: data.status,
  issue_number: data.issue_number,
  issue_url: data.issue_url,
  run_id: data.run_id,
  evidence_comment_prepared: !!data.comment_body,
  evidence_comment_length: data.comment_body ? data.comment_body.length : 0,
  next_action: 'Issue-Kommentar manuell oder via GitHub API posten. Labels auf agent:done + evidence:attached setzen.'
};

return result;
